189→export const uploadOpinionReplyService = async(parent_id, opinion, user_id) =>{
190→    if(!parent_id || !user_id){
191→        console.error('parentid or userid is undefined');
192→        throw {status: 400, error:'parentid or userid is undefined'};
193→    }
194→    if(!opinion || !typeof(opinion) === 'string'){
195→        console.error('opinion is undefined or opinion is not a string')
196→        throw {status: 'opinion is undefined or opinion is not a string'};
197→    }
198→
199→    const {data: parentOpinion, error: errorParentOpinion} = await supabase
200→    .from('opinions')
201→    .select('user_id')
202→    .eq('id', parent_id)
203→    .maybeSingle();
204→
205→    if(errorParentOpinion){
206→        console.error('supabase error while fetching parent opinion', errorParentOpinion.message);
207→        throw {status: 500, error: 'supabase error while fetching parent opinion'};
208→    }
209→    if(!parentOpinion?.user_id){
210→        console.error('parent opinion not found');
211→        throw {status: 404, error: 'parent opinion not found'};
212→    }
213→
214→    const receiver_id = parentOpinion.user_id;
215→    const isOwner = user_id === receiver_id;
216→
217→    const insertNotifPromise = supabase
218→    .from('notification_opinions')
219→    .insert({type: 'reply', read: false, receiver_id: receiver_id, sender_id: user_id, opinion_id: parent_id})
220→
221→    const insertOpinionReplyPromise = supabase
222→    .from('opinions')
223→    .insert({user_id: user_id, parent_id: parent_id, opinion: opinion})
224→
225→    const [ insertNotif, insertOpinionReply] = await Promise.all([
226→        isOwner ? Promise.resolve({error: null}) : insertNotifPromise, insertOpinionReplyPromise
227→    ])
228→    const {data: uploadOpinionReply, error: errorUploadOpinionReply} = insertOpinionReply;
229→    const {data: insertNotifResult, error: errorInsertNotif} = insertNotif;
230→
231→    if(errorUploadOpinionReply || errorInsertNotif) {
232→        console.error('supabase error:', errorInsertNotif.message ||errorUploadOpinionReply.message);
233→        return {status: 500, error: 'supabaser error'}
234→    }
235→
236→    return {message: 'success'};
237→}
