365→export const addFollowsService = async(followerId, followingId) => {
366→    if(!followerId || !followingId){
367→        console.error('followerId or followingId is undefined');
368→        throw {status: 400, error: 'followerId or followingId is undefined'};
369→    }
370→
371→    const {data: existing, error: errorExisting} = await supabase
372→    .from('follows')
373→    .select('*')
374→    .eq('follower_id', followerId)
375→    .eq('following_id', followingId)
376→    .maybeSingle();
377→
378→    if(errorExisting){
379→        console.error('supabase error while checking existing following:', errorExisting.message);
380→        throw {status: 500, error: 'supabase error while checking existing following'}
381→    }
382→
383→    if(existing){
384→        const {data: removeData, error: errorRemoveData} = await supabase
385→        .from('follows')
386→        .delete()
387→        .eq('follower_id', followerId)
388→        .eq('following_id', followingId)
389→
390→        if(errorRemoveData){
391→            console.error('supabase error while deleting follow data:', errorRemoveData.message);
392→            throw {status: 500, error: 'supabase error while deleting follow data'};
393→        }
394→
395→        return {message: 'deleted follows data'};
396→    } else {
397→        const data = {
398→            follower_id: followerId,
399→            following_id: followingId,
400→        }
401→
402→        const {data: inserData,  error: errorInserData} = await supabase
403→        .from('follows')
404→        .insert(data)
405→
406→        if(errorInserData){
407→            console.error('supabase error while inserting follow data:', errorInserData.message);
408→            throw {status: 500, error: 'supabase error while inserting follow data:'}
409→        }
410→
411→        // Create follow notification (skip if self-follow)
412→        if (followerId !== followingId) {
413→            await supabase
414→                .from('notifications')
415→                .insert({
416→                    sender_id: followerId,
417→                    receiver_id: followingId,
418→                    type: 'follow',
419→                    read: false
420→                });
421→        }
422→
423→        return {message: 'success'};
424→    }
425→}
